export enum SkillType {
  READING = 'Reading',
  LISTENING = 'Listening',
  SPEAKING = 'Speaking',
  WRITING = 'Writing'
}

export interface Lesson {
  id: string;
  title: string;
  description: string;
  content: string;
  type: SkillType;
  level: 'Beginner' | 'Intermediate' | 'Advanced';
}

export interface Exercise {
  id: string;
