export function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function encode(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createPcmBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { decode, decodeAudioData, createPcmBlob } from '../services/audioUtils';

const GeminiLiveTutor: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState<'idle' | 'connecting' | 'listening' | 'speaking'>('idle');
  const [transcripts, setTranscripts] = useState<{ role: 'user' | 'model'; text: string }[]>([]);

  const inputAudioCtxRef = useRef<AudioContext | null>(null);
  const outputAudioCtxRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');

  const stopSession = useCallback(() => {
    if (sessionRef.current) {
      // Logic to close session if SDK provides it, otherwise we just stop streams
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    if (inputAudioCtxRef.current) inputAudioCtxRef.current.close();
    if (outputAudioCtxRef.current) outputAudioCtxRef.current.close();

    setIsActive(false);
    setStatus('idle');
  }, []);

  const startSession = async () => {
    try {
      setStatus('connecting');
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      inputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            console.log('Gemini Live Connection Opened');
            setIsActive(true);
            setStatus('listening');

            const source = inputAudioCtxRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioCtxRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then((session) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioCtxRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Transcription
            if (message.serverContent?.outputTranscription) {
              currentOutputTranscription.current += message.serverContent.outputTranscription.text;
            } else if (message.serverContent?.inputTranscription) {
              currentInputTranscription.current += message.serverContent.inputTranscription.text;
            }

            if (message.serverContent?.turnComplete) {
              const userText = currentInputTranscription.current;
              const modelText = currentOutputTranscription.current;
              if (userText || modelText) {
                setTranscripts(prev => [
                  ...prev, 
                  { role: 'user', text: userText || '(Hablando...)' },
                  { role: 'model', text: modelText || '(Respondiendo...)' }
                ]);
              }
              currentInputTranscription.current = '';
              currentOutputTranscription.current = '';
            }

            // Handle Audio
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outputAudioCtxRef.current) {
              setStatus('speaking');
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioCtxRef.current.currentTime);
              const audioBuffer = await decodeAudioData(
                decode(base64Audio),
                outputAudioCtxRef.current,
                24000,
                1
              );
              const source = outputAudioCtxRef.current.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outputAudioCtxRef.current.destination);
              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setStatus('listening');
              });
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setStatus('listening');
            }
          },
          onerror: (e) => {
            console.error('Gemini Live Error:', e);
            stopSession();
          },
          onclose: () => {
            console.log('Gemini Live Closed');
            stopSession();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: 'Eres un profesor de inglés nativo y paciente llamado James. Tu objetivo es ayudar al usuario a practicar su inglés básico de forma conversacional. Corrige sus errores de forma amable y mantén la conversación simple pero fluida.',
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } }
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {}
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Failed to start session', err);
      setStatus('idle');
    }
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200">
      <div className="bg-indigo-600 p-6 text-white flex justify-between items-center">
        <div>
          <h2 className="text-xl font-bold flex items-center gap-2">
            <i className="fas fa-robot"></i> Tutor de Voz IA
          </h2>
          <p className="text-indigo-100 text-sm">Practica Speaking en tiempo real con James</p>
        </div>
        <div className="flex items-center gap-3">
          {isActive ? (
            <button 
              onClick={stopSession}
              className="bg-red-500 hover:bg-red-600 px-4 py-2 rounded-full font-medium transition-colors flex items-center gap-2"
            >
              <i className="fas fa-stop"></i> Finalizar
            </button>
          ) : (
            <button 
              onClick={startSession}
              disabled={status === 'connecting'}
              className="bg-white text-indigo-600 hover:bg-indigo-50 px-6 py-2 rounded-full font-bold shadow-lg transition-all transform active:scale-95 disabled:opacity-50"
            >
              {status === 'connecting' ? 'Conectando...' : 'Comenzar Práctica'}
            </button>
          )}
        </div>
      </div>

      <div className="h-96 overflow-y-auto p-6 bg-slate-50 flex flex-col gap-4">
        {transcripts.length === 0 && !isActive && (
          <div className="flex flex-col items-center justify-center h-full text-slate-400">
            <i className="fas fa-microphone-lines text-5xl mb-4"></i>
            <p className="text-center italic">Presiona "Comenzar" para hablar con tu tutor.</p>
          </div>
        )}

        {transcripts.map((t, i) => (
          <div key={i} className={`flex ${t.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] p-3 rounded-2xl ${
              t.role === 'user' 
                ? 'bg-indigo-100 text-indigo-900 rounded-tr-none' 
                : 'bg-white shadow-sm border border-slate-200 text-slate-700 rounded-tl-none'
            }`}>
              <p className="text-sm">{t.text}</p>
            </div>
          </div>
        ))}

        {isActive && (
          <div className="flex justify-center mt-auto">
            <div className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-600 rounded-full animate-pulse border border-indigo-200">
              <i className={`fas ${status === 'speaking' ? 'fa-volume-high' : 'fa-microphone'}`}></i>
              <span className="text-xs font-bold uppercase tracking-wider">
                {status === 'speaking' ? 'James está hablando...' : 'Escuchándote...'}
              </span>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-slate-100 border-t border-slate-200 text-xs text-slate-500 text-center">
        Powered by Gemini 2.5 Native Audio
      </div>
    </div>
  );
};

export default GeminiLiveTutor;

import React, { useState } from 'react';
import { GoogleGenAI } from '@google/genai';

const WritingModule: React.FC = () => {
  const [text, setText] = useState('');
  const [feedback, setFeedback] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const checkWriting = async () => {
    if (!text.trim()) return;
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analiza el siguiente texto en inglés escrito por un estudiante básico. Proporciona correcciones gramaticales, sugerencias de vocabulario y una explicación breve en español de por qué se hicieron los cambios: \n\n"${text}"`,
        config: {
          systemInstruction: 'Eres un editor experto de inglés. Sé constructivo y educativo.',
        }
      });
      setFeedback(response.text || 'No se pudo obtener feedback.');
    } catch (error) {
      setFeedback('Error al conectar con el tutor de escritura.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
          <i className="fas fa-pen-nib text-indigo-500"></i> Ejercicio de Escritura
        </h3>
        <p className="text-slate-600 mb-4">Escribe un párrafo corto sobre tus planes para el próximo fin de semana (mínimo 30 palabras):</p>
        <textarea 
          value={text}
          onChange={(e) => setText(e.target.value)}
          className="w-full h-40 p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
          placeholder="E.g. Next weekend, I am going to visit my family..."
        />
        <div className="mt-4 flex justify-between items-center">
          <span className="text-sm text-slate-400">{text.split(/\s+/).filter(x => x).length} palabras</span>
          <button 
            onClick={checkWriting}
            disabled={loading || text.length < 10}
            className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-semibold hover:bg-indigo-700 disabled:opacity-50 transition-colors flex items-center gap-2"
          >
            {loading ? <i className="fas fa-spinner animate-spin"></i> : <i className="fas fa-check"></i>}
            Corregir mi texto
          </button>
        </div>
      </div>

      {feedback && (
        <div className="bg-indigo-50 p-6 rounded-2xl border border-indigo-100 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <h4 className="font-bold text-indigo-900 mb-2 flex items-center gap-2">
            <i className="fas fa-comment-dots"></i> Feedback del Tutor:
          </h4>
          <div className="prose prose-indigo max-w-none text-indigo-800 text-sm whitespace-pre-wrap">
            {feedback}
          </div>
        </div>
      )}
    </div>
  );
};

export default WritingModule;

import React, { useState } from 'react';
import { GoogleGenAI } from '@google/genai';

const ReadingModule: React.FC = () => {
  const [story, setStory] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const generateStory = async (topic: string) => {
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Genera una historia muy corta (máximo 100 palabras) en inglés básico para principiantes sobre el tema: ${topic}. Incluye una lista de 5 palabras clave con su traducción al español al final.`,
      });
      setStory(response.text || 'No se pudo generar la historia.');
    } catch (error) {
      setStory('Error al conectar con el generador de historias.');
    } finally {
      setLoading(false);
    }
  };

  const resources = [
    { name: 'LingQ', desc: 'Material real con audios.', icon: 'fa-language', url: 'https://www.lingq.com/' },
    { name: 'Beelinguapp', desc: 'Historias bilingües simultáneas.', icon: 'fa-book-open', url: 'https://beelinguapp.com/' },
    { name: 'Readlang', desc: 'Lee y traduce al momento.', icon: 'fa-highlighter', url: 'https://readlang.com/' },
    { name: 'BBC Mundo', desc: 'Noticias para práctica avanzada.', icon: 'fa-newspaper', url: 'https://www.bbc.com/mundo' },
  ];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <section>
        <div className="bg-gradient-to-r from-blue-600 to-indigo-700 p-8 rounded-3xl text-white shadow-lg mb-6">
          <h2 className="text-2xl font-bold mb-2">Generador de Historias Cortas</h2>
          <p className="text-blue-100 mb-6">Elige un tema y Gemini creará una lectura adaptada para ti.</p>
          <div className="flex flex-wrap gap-3">
            {['A Day at the Beach', 'The Secret Forest', 'My Future Robot', 'Traveling to London'].map(topic => (
              <button 
                key={topic}
                onClick={() => generateStory(topic)}
                disabled={loading}
                className="bg-white/20 hover:bg-white/30 px-4 py-2 rounded-xl text-sm font-medium backdrop-blur-sm transition-all active:scale-95 disabled:opacity-50"
              >
                {topic}
              </button>
            ))}
          </div>
        </div>

        {loading && (
          <div className="flex flex-col items-center py-12 text-slate-400">
            <i className="fas fa-spinner animate-spin text-4xl mb-4 text-indigo-500"></i>
            <p>Escribiendo tu historia personalizada...</p>
          </div>
        )}

        {story && !loading && (
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-200 prose prose-slate max-w-none">
            <div className="flex justify-between items-center mb-6 not-prose">
              <span className="bg-indigo-100 text-indigo-700 text-xs font-bold px-3 py-1 rounded-full uppercase">Lectura Básica</span>
              <button onClick={() => setStory(null)} className="text-slate-400 hover:text-red-500"><i className="fas fa-times"></i></button>
            </div>
            <div className="whitespace-pre-wrap text-slate-700 leading-relaxed font-serif text-lg">
              {story}
            </div>
          </div>
        )}
      </section>

      <section>
        <h3 className="text-xl font-bold text-slate-800 mb-4 px-2">Plataformas de Lectura Recomendadas</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {resources.map(res => (
            <a 
              key={res.name}
              href={res.url}
              target="_blank"
              rel="noopener noreferrer"
              className="bg-white p-5 rounded-2xl border border-slate-200 hover:border-indigo-300 hover:shadow-md transition-all group"
            >
              <div className="w-10 h-10 bg-slate-50 rounded-lg flex items-center justify-center text-slate-400 group-hover:bg-indigo-50 group-hover:text-indigo-600 transition-colors mb-4">
                <i className={`fas ${res.icon} text-lg`}></i>
              </div>
              <h4 className="font-bold text-slate-900">{res.name}</h4>
              <p className="text-xs text-slate-500 mt-1">{res.desc}</p>
            </a>
          ))}
        </div>
      </section>
    </div>
  );
};

export default ReadingModule;

import React, { useState, useRef } from 'react';
import { GoogleGenAI, Modality } from '@google/genai';
import { decode, decodeAudioData } from '../services/audioUtils';

const ListeningModule: React.FC = () => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [shadowingText, setShadowingText] = useState<string>('The weather is lovely today. I want to go for a walk in the park.');
  const [loadingAudio, setLoadingAudio] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);

  const playTTS = async (text: string) => {
    setLoadingAudio(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `Say clearly and slowly: ${text}` }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        const buffer = await decodeAudioData(decode(base64Audio), audioContextRef.current, 24000, 1);
        const source = audioContextRef.current.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => setIsPlaying(false);
        setIsPlaying(true);
        source.start();
      }
    } catch (error) {
      console.error('Error in TTS:', error);
    } finally {
      setLoadingAudio(false);
    }
  };

  const podcasts = [
    { title: 'News in Slow Spanish', type: 'Podcast', link: '#' },
    { title: 'Radio Ambulante', type: 'Advanced', link: '#' },
    { title: 'Coffee Break Spanish', type: 'Learning', link: '#' },
  ];

  const youtubeChannels = [
    { name: 'Easy Spanish', desc: 'Entrevistas en la calle.', color: 'bg-red-500' },
    { name: 'Butterfly Spanish', desc: 'Clases estructuradas.', color: 'bg-orange-500' },
  ];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Shadowing Exercise */}
        <div className="lg:col-span-2 bg-white rounded-3xl p-8 shadow-sm border border-slate-200">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-xl font-bold flex items-center gap-2">
              <i className="fas fa-ghost text-indigo-500"></i> Práctica de Shadowing
            </h3>
            <span className="text-xs bg-indigo-50 text-indigo-600 px-3 py-1 rounded-full font-bold">IA VOICE</span>
          </div>
          <p className="text-slate-600 text-sm mb-6">
            La técnica de **shadowing** consiste en repetir lo que escuchas al mismo tiempo. Escucha la pronunciación de la IA e inténtalo.
          </p>

          <div className="bg-slate-50 p-6 rounded-2xl border border-dashed border-slate-300 mb-6">
             <textarea 
               value={shadowingText}
               onChange={(e) => setShadowingText(e.target.value)}
               className="w-full bg-transparent border-none resize-none focus:ring-0 text-xl font-medium text-slate-700 italic text-center h-24"
             />
          </div>

          <div className="flex justify-center">
            <button 
              onClick={() => playTTS(shadowingText)}
              disabled={isPlaying || loadingAudio}
              className={`w-20 h-20 rounded-full flex items-center justify-center transition-all shadow-xl shadow-indigo-200 ${
                isPlaying ? 'bg-red-500 text-white animate-pulse' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95'
              }`}
            >
              {loadingAudio ? (
                <i className="fas fa-spinner animate-spin text-2xl"></i>
              ) : (
                <i className={`fas ${isPlaying ? 'fa-stop' : 'fa-play'} text-2xl`}></i>
              )}
            </button>
          </div>
        </div>

        {/* Podcasts Section */}
        <div className="bg-slate-900 rounded-3xl p-6 text-white">
          <h3 className="font-bold mb-4 flex items-center gap-2">
            <i className="fas fa-podcast text-indigo-400"></i> Podcasts Recomendados
          </h3>
          <div className="space-y-3">
            {podcasts.map(p => (
              <div key={p.title} className="p-4 bg-white/10 rounded-xl hover:bg-white/20 transition-colors flex items-center justify-between group cursor-pointer">
                <div>
                  <p className="font-bold text-sm">{p.title}</p>
                  <p className="text-[10px] text-indigo-300 uppercase tracking-widest">{p.type}</p>
                </div>
                <i className="fas fa-external-link-alt text-xs opacity-0 group-hover:opacity-100 transition-opacity"></i>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* YouTube Section */}
      <section>
        <h3 className="text-xl font-bold text-slate-800 mb-4 px-2">Recursos Audiovisuales (YouTube)</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {youtubeChannels.map(yt => (
            <div key={yt.name} className="bg-white p-6 rounded-2xl border border-slate-200 flex items-center gap-6 hover:shadow-md transition-shadow">
               <div className={`w-16 h-16 ${yt.color} rounded-2xl flex items-center justify-center text-white text-2xl`}>
                 <i className="fab fa-youtube"></i>
               </div>
               <div>
                 <h4 className="font-bold text-slate-900">{yt.name}</h4>
                 <p className="text-sm text-slate-500">{yt.desc}</p>
                 <button className="mt-2 text-xs font-bold text-indigo-600 hover:underline">Ver canal <i className="fas fa-chevron-right text-[8px]"></i></button>
               </div>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

export default ListeningModule;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality } from '@google/genai';
import { decode, decodeAudioData } from '../services/audioUtils';

const ListeningModule: React.FC = () => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [shadowingText, setShadowingText] = useState<string>('The weather is lovely today. I want to go for a walk in the park.');
  const [loadingAudio, setLoadingAudio] = useState(false);
  const [loadingNewPhrase, setLoadingNewPhrase] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);

  const fetchNewPhrase = async () => {
    setLoadingNewPhrase(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: 'Generate a single short, natural sentence in basic English for a student to practice speaking (shadowing). Maximum 12 words.',
      });
      const newPhrase = response.text?.trim().replace(/^["']|["']$/g, '') || shadowingText;
      setShadowingText(newPhrase);
    } catch (error) {
      console.error('Error fetching new phrase:', error);
    } finally {
      setLoadingNewPhrase(false);
    }
  };

  const playTTS = async (text: string) => {
    if (isPlaying) return;
    setLoadingAudio(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `Say clearly and at a natural pace for a student: ${text}` }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        const buffer = await decodeAudioData(decode(base64Audio), audioContextRef.current, 24000, 1);
        const source = audioContextRef.current.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => setIsPlaying(false);
        setIsPlaying(true);
        source.start();
      }
    } catch (error) {
      console.error('Error in TTS:', error);
      setIsPlaying(false);
    } finally {
      setLoadingAudio(false);
    }
  };

  const podcasts = [
    { title: 'News in Slow English', type: 'Initial/Intermediate', link: 'https://www.newsinslowenglish.com/' },
    { title: '6 Minute English (BBC)', type: 'Advanced/Practical', link: 'https://www.bbc.co.uk/learningenglish/english/features/6-minute-english' },
    { title: 'Coffee Break English', type: 'Structured Lessons', link: 'https://coffeebreaklanguages.com/coffeebreakenglish/' },
  ];

  const youtubeChannels = [
    { 
      name: 'Easy English', 
      desc: 'Entrevistas reales en la calle con subtítulos claros.', 
      color: 'bg-red-500', 
      url: 'https://www.youtube.com/@EasyEnglishLearning' 
    },
    { 
      name: 'Butterfly English', 
      desc: 'Clases estructuradas de gramática y vocabulario.', 
      color: 'bg-orange-500', 
      url: 'https://www.youtube.com/@ButterflyEnglish' 
    },
  ];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Shadowing Exercise */}
        <div className="lg:col-span-2 bg-white rounded-3xl p-8 shadow-sm border border-slate-200 flex flex-col">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-xl font-bold flex items-center gap-2">
              <i className="fas fa-ghost text-indigo-500"></i> Práctica de Shadowing
            </h3>
            <button 
              onClick={fetchNewPhrase}
              disabled={loadingNewPhrase || isPlaying}
              className="text-indigo-600 hover:bg-indigo-50 px-3 py-1.5 rounded-lg text-sm font-bold transition-colors flex items-center gap-2 disabled:opacity-50"
            >
              <i className={`fas fa-arrows-rotate ${loadingNewPhrase ? 'animate-spin' : ''}`}></i>
              Cambiar Frase
            </button>
          </div>
          <p className="text-slate-600 text-sm mb-6">
            La técnica de **shadowing** consiste en repetir lo que escuchas al mismo tiempo. Escucha la pronunciación de la IA e inténtalo.
          </p>

          <div className="bg-slate-50 p-6 rounded-2xl border border-dashed border-slate-300 mb-6 flex-1 flex items-center justify-center">
             {loadingNewPhrase ? (
               <div className="animate-pulse flex space-x-4">
                 <div className="h-4 w-48 bg-slate-200 rounded"></div>
               </div>
             ) : (
               <textarea 
                 value={shadowingText}
                 onChange={(e) => setShadowingText(e.target.value)}
                 className="w-full bg-transparent border-none resize-none focus:ring-0 text-xl md:text-2xl font-medium text-slate-700 italic text-center h-24"
                 placeholder="Escribe algo para practicar..."
               />
             )}
          </div>

          <div className="flex justify-center gap-4">
            <button 
              onClick={() => playTTS(shadowingText)}
              disabled={isPlaying || loadingAudio || loadingNewPhrase}
              className={`w-20 h-20 rounded-full flex items-center justify-center transition-all shadow-xl shadow-indigo-200 ${
                isPlaying ? 'bg-red-500 text-white animate-pulse' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95'
              } disabled:opacity-50`}
            >
              {loadingAudio ? (
                <i className="fas fa-spinner animate-spin text-2xl"></i>
              ) : (
                <i className={`fas ${isPlaying ? 'fa-stop' : 'fa-play'} text-2xl`}></i>
              )}
            </button>
          </div>
        </div>

        {/* Podcasts Section */}
        <div className="bg-slate-900 rounded-3xl p-6 text-white flex flex-col">
          <h3 className="font-bold mb-4 flex items-center gap-2">
            <i className="fas fa-podcast text-indigo-400"></i> Podcasts Recomendados
          </h3>
          <div className="space-y-3 flex-1 overflow-y-auto">
            {podcasts.map(p => (
              <a 
                key={p.title} 
                href={p.link} 
                target="_blank" 
                rel="noopener noreferrer"
                className="p-4 bg-white/10 rounded-xl hover:bg-white/20 transition-colors flex items-center justify-between group"
              >
                <div>
                  <p className="font-bold text-sm">{p.title}</p>
                  <p className="text-[10px] text-indigo-300 uppercase tracking-widest">{p.type}</p>
                </div>
                <i className="fas fa-external-link-alt text-xs opacity-60 group-hover:opacity-100 transition-opacity"></i>
              </a>
            ))}
          </div>
          <div className="mt-4 p-3 bg-indigo-500/20 rounded-xl border border-white/10">
            <p className="text-[10px] text-indigo-200 italic leading-tight">
              Nota: Estos podcasts están diseñados específicamente para estudiantes de idiomas.
            </p>
          </div>
        </div>
      </div>

      {/* YouTube Section */}
      <section>
        <h3 className="text-xl font-bold text-slate-800 mb-4 px-2">Recursos Audiovisuales (YouTube)</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {youtubeChannels.map(yt => (
            <a 
              key={yt.name} 
              href={yt.url} 
              target="_blank" 
              rel="noopener noreferrer"
              className="bg-white p-6 rounded-2xl border border-slate-200 flex items-center gap-6 hover:shadow-md transition-shadow group"
            >
               <div className={`w-16 h-16 ${yt.color} rounded-2xl flex items-center justify-center text-white text-2xl group-hover:scale-105 transition-transform`}>
                 <i className="fab fa-youtube"></i>
               </div>
               <div className="flex-1">
                 <h4 className="font-bold text-slate-900 flex items-center gap-2">
                   {yt.name}
                   <i className="fas fa-external-link-alt text-[10px] text-slate-300"></i>
                 </h4>
                 <p className="text-sm text-slate-500">{yt.desc}</p>
                 <span className="mt-2 text-xs font-bold text-indigo-600 block">Visitar canal</span>
               </div>
            </a>
          ))}
