            onClick={fetchNewPhrase} 
            disabled={loadingNewPhrase || isPlaying}
            className="text-xs font-bold text-indigo-600 uppercase tracking-widest hover:underline disabled:opacity-30"
          >
            {loadingNewPhrase ? 'Generando...' : 'Nueva Frase'}
