                if (sourcesRef.current.size === 0) setStatus('listening');
              };
              source.start();
              sourcesRef.current.add(source);
            }
          },
          onerror: (e) => { setError("Error de conexión con James."); stopSession(); },
          onclose: () => stopSession()
        },
        config: {
